import { WEDDING_CONFIG } from './weddingConfig';

export const createSvgTexture = (svgString: string) => {
  return `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svgString)}`;
};

const escapeXml = (unsafe: string) => {
  if (typeof unsafe !== 'string') return unsafe;
  return unsafe.replace(/[<>&"']/g, (c) => {
    switch (c) {
      case '<': return '&lt;';
      case '>': return '&gt;';
      case '&': return '&amp;';
      case '"': return '&quot;';
      case "'": return '&apos;';
      default: return c;
    }
  });
};

export const generateElementSvg = (element: any) => {
  const { 
    text, 
    lines, 
    font = 'serif', 
    fontFamily,
    style = 'normal', 
    weight = 'normal', 
    size = 24, 
    x = 600,
    y = 400, 
    align = 'middle',
    color = 'text', 
    letterSpacing = 0, 
    opacity = 1,
    lineHeight = 40
  } = element;

  let fontStack = fontFamily;
  if (!fontStack) {
    if (font === 'serif') fontStack = 'Georgia, serif';
    else if (font === 'sans') fontStack = 'Arial, sans-serif';
    else if (font === 'cursive') fontStack = "'Monsieur La Doulaise', cursive";
    else fontStack = 'Georgia, serif';
  }
  const fillColor = (WEDDING_CONFIG.colors as any)[color] || color;

  let content = '';
  if (lines) {
    content = lines.map((line: string, i: number) => `
      <text 
        x="${x}" 
        y="${y + (i * lineHeight)}" 
        font-family="${fontStack}" 
        font-style="${style}" 
        font-weight="${weight}"
        font-size="${size}" 
        text-anchor="${align}" 
        fill="${fillColor}" 
        opacity="${opacity}"
        letter-spacing="${letterSpacing}"
      >${escapeXml(line)}</text>
    `).join('');
  } else {
    content = `
      <text 
        x="${x}" 
        y="${y}" 
        font-family="${fontStack}" 
        font-style="${style}" 
        font-weight="${weight}"
        font-size="${size}" 
        text-anchor="${align}" 
        fill="${fillColor}" 
        opacity="${opacity}"
        letter-spacing="${letterSpacing}"
      >${escapeXml(text)}</text>
    `;
  }

  return createSvgTexture(`
    <svg width="1200" height="800" xmlns="http://www.w3.org/2000/svg">
<defs><style>
@font-face { font-family: 'Monsieur La Doulaise'; src: url('data:font/ttf;base64,') format('truetype'); }
</style>
</defs>
      ${content}
    </svg>
  `);
};
